import{_ as o,o as r,c as a,a2 as e}from"./chunks/framework.DvFsUg-r.js";const m=JSON.parse('{"title":"플랫폼 관리 기능 이관 — 명세에서 MVP 검증까지","description":"","frontmatter":{"slug":"platform-admin-migration","title":"플랫폼 관리 기능 이관 — 명세에서 MVP 검증까지","authors":[],"tags":["spec-kit","sdd","spring-boot","mybatis","migration","platform","jwt","audit"],"created":"2026-05-30 23:58 (KST)","date":"2026-05-30T14:58:00.000Z"},"headers":[],"relativePath":"journal/2026-05-30-platform-admin-migration.md","filePath":"journal/2026-05-30-platform-admin-migration.md","lastUpdated":1781092690000}'),d={name:"journal/2026-05-30-platform-admin-migration.md"};function n(s,t,i,c,g,l){return r(),a("div",null,[...t[0]||(t[0]=[e('<p>기존 사내 플랫폼(<strong>Clear Platform</strong>)의 엔터프라이즈 관리 기능 <strong>22종</strong>(로그인·RBAC· 공통코드·다국어·메일·결재·권한신청·감사 이력 등)을 이 저장소의 에이전트 앱으로 <strong>이관</strong>하는 작업을 시작했다. 설계는 Spec Kit(<code>specs/004-platform-admin-migration</code>) 으로 진행했고, 이 글은 그 과정과 — 특히 <strong>Spring Boot 4 베이스라인을 실제로 빌드되게 만드는 과정</strong> — 의 개발 로그다.</p><h2 id="sdd-흐름대로-진행" tabindex="-1">SDD 흐름대로 진행 <a class="header-anchor" href="#sdd-흐름대로-진행" aria-label="Permalink to &quot;SDD 흐름대로 진행&quot;">​</a></h2><p>명세 주도 개발(SDD) 단계를 순서대로 밟았다.</p><ol><li><strong>specify</strong> — 22개 기능을 7개 그룹(인증 / 시스템관리 / 조직·RBAC / 메일 / 결재 / 권한신청 / 이력관리)으로 정리. 원본의 불량분석·AI/RAG·Spring Batch 는 명시적 비목표.</li><li><strong>clarify</strong> — 핵심 4건 확정: 저장소 <strong>Oracle 유지</strong>, 표면 <strong>백엔드 + VuGrid 목록 데모</strong>, 결재 <strong>다단계 결재선</strong>, 감사 이력 <strong>1년 보존</strong>.</li><li><strong>plan</strong> — 소스의 4-레이어(Controller → Service → Mapper → XML) 구조를 타겟 패키지 <code>com.example.agent.platform</code>으로 적응 이식. 버전 고정·소스↔타겟 모듈 매핑.</li><li><strong>analyze</strong> — spec·plan·tasks 교차 검사로 CRITICAL 1·HIGH 1·MEDIUM 4 발견 → 전부 보정(버전 고정, SQL 이력 필수화, 결재 SLA, 메일 범위 명문화 등) → 0건.</li><li><strong>tasks</strong> — 82개 태스크를 유저스토리별로 분해(+ 호환성 스파이크 T0a).</li><li><strong>implement</strong> — MVP 증분(Setup + Foundational + US1 로그인/접근제어)부터.</li></ol><h2 id="진짜-난관-spring-boot-4-베이스라인" tabindex="-1">진짜 난관: Spring Boot 4 베이스라인 <a class="header-anchor" href="#진짜-난관-spring-boot-4-베이스라인" aria-label="Permalink to &quot;진짜 난관: Spring Boot 4 베이스라인&quot;">​</a></h2><p>앱은 Spring Boot 4.0.0 / Spring AI 2.0.0 으로 스캐폴드만 있고 <strong>빌드된 적이 없는</strong> 상태였다. 로컬에 Gradle 9.5.1 과 JDK 21 을 갖춰 직접 빌드하자, 한 겹씩 문제가 드러났다. 고친 순서대로 정리한다.</p><table tabindex="0"><thead><tr><th>증상</th><th>원인</th><th>해결</th></tr></thead><tbody><tr><td>모든 starter 버전이 빈 채 해석 실패</td><td><code>io.spring.dependency-management</code> 1.1.7 이 Boot4/Gradle9 에서 BOM 미적용</td><td>Gradle 네이티브 <code>platform()</code> BOM 으로 전환</td></tr><tr><td><code>spring-ai-bom:2.0.0</code> 없음</td><td>2.0.0 <strong>GA 미배포</strong>(마일스톤만 존재)</td><td>현존 최신 2.x 인 <code>2.0.0-M8</code> 로 고정</td></tr><tr><td><code>spring-boot-starter-aop</code> 버전 없음</td><td>Boot4 GA 에 해당 스타터 부재</td><td><code>aspectjweaver</code>(BOM 관리) 직접 추가</td></tr><tr><td><code>No qualifying bean DataSource</code></td><td><code>spring-jdbc</code> 만으론 자동구성·풀 부재</td><td><code>spring-boot-starter-jdbc</code>(HikariCP) 추가</td></tr><tr><td>테이블 없음(DB empty) → 로그인 500</td><td>Boot4 가 <strong>Liquibase 자동구성을 별도 모듈로 분리</strong></td><td><code>spring-boot-starter-liquibase</code> 추가</td></tr><tr><td>테스트 컴파일 실패</td><td>Boot4 가 <strong>MockMvc 슬라이스를 분리</strong></td><td><code>@AutoConfigureMockMvc</code> 대신 <code>RANDOM_PORT</code> + <code>RestClient</code>(실 HTTP)</td></tr><tr><td>record 컴파일 오류</td><td><code>ApiResponse</code> 의 <code>success</code> 컴포넌트 접근자와 무인자 팩토리 충돌</td><td>무인자 팩토리를 <code>ok()</code> 로 개명</td></tr></tbody></table><p>요지는 <strong>Spring Boot 4 가 자동구성을 기술별 모듈로 잘게 쪼갰다</strong>는 점이다. jdbc· liquibase·aop 가 각각 별도 스타터/아티팩트로 빠져, 필요한 조각을 명시적으로 가져와야 했다.</p><h2 id="t0a-—-mybatis-×-spring-framework-7-호환" tabindex="-1">T0a — MyBatis × Spring Framework 7 호환 <a class="header-anchor" href="#t0a-—-mybatis-×-spring-framework-7-호환" aria-label="Permalink to &quot;T0a — MyBatis × Spring Framework 7 호환&quot;">​</a></h2><p>가장 불확실했던 가정은 &quot;<strong>MyBatis 가 Spring Framework 7(Boot 4)에서 동작하는가</strong>&quot; 였다(plan 의 스파이크 T0a, 헌법 원칙2 게이트). 스타터 의존을 피하려고 <code>mybatis-spring</code> 3.0.4 를 <strong>직접 <code>SqlSessionFactory</code> 빈</strong>으로 구성했고, 통합 테스트에서 매퍼 등록과 실제 SQL 실행이 H2(Oracle 호환 모드)에서 <strong>런타임 통과</strong> 하는 것을 확인했다. T0a 해소.</p><h2 id="결과-—-mvp-7-7-통과" tabindex="-1">결과 — MVP 7/7 통과 <a class="header-anchor" href="#결과-—-mvp-7-7-통과" aria-label="Permalink to &quot;결과 — MVP 7/7 통과&quot;">​</a></h2><p>로컬과 클린 CI 양쪽에서 <code>gradle test</code> <strong>7/7 통과</strong>:</p><ul><li><strong>기반</strong>: 컨텍스트 로드(Boot4 + Spring AI 2.0.0-M8 + langgraph4j 1.8.17 + MyBatis + Liquibase + Security 공존), actuator 공개, 보호 API 미인증 401.</li><li><strong>US1 인증</strong>: 로그인 성공(토큰 발급) / 오인증 401 / 미인증 401 / 내 정보 200 (<code>admin</code>·<code>ADMIN</code>). 로그인 성공·실패가 모두 로그인 이력에 기록.</li></ul><p>스키마는 Liquibase 로 <code>SYS_*</code>·<code>AUDIT_*</code> <strong>26개 테이블</strong>을 Oracle·H2 공용 제네릭 타입으로 생성하고, 관리자·역할·메뉴·코드·메시지 최소 시드를 넣었다.</p><h2 id="남은-일" tabindex="-1">남은 일 <a class="header-anchor" href="#남은-일" aria-label="Permalink to &quot;남은 일&quot;">​</a></h2><p>이번엔 MVP(US1)까지다. 다음 증분은 US2(RBAC: 부서·사용자·역할·메뉴·메뉴권한)이고, 이어서 코드·다국어·설정 → 감사 7종 → 다단계 결재 → 권한신청 → 메일·파일 순으로 간다. 알려진 후속 과제: 메뉴 세분권한 평가, SQL 실행 이력(datasource-proxy) 연동, 시드 관리자 비밀번호 해시화, 무상태 로그아웃 denylist.</p><p>설계 산출물 전체는 <code>specs/004-platform-admin-migration/</code> 에 있다.</p>',17)])])}const u=o(d,[["render",n]]);export{m as __pageData,u as default};
